title: $:/plugins/rimir/llm-connect/adapter-azure
type: application/javascript
module-type: library

Azure OpenAI API adapter

\*/
(function() {

"use strict";

var base = require("$:/plugins/rimir/llm-connect/adapter-openai-base");

exports.name = "azure";

exports.buildRequest = function(messages, tools, config) {
	var endpoint = (config.endpoint || "").replace(/\/+$/, "");
	var deployment = config.deployment || "";
	var apiVersion = config.apiVersion || "2025-04-01-preview";
	var maxTokens = parseInt(config.maxTokens) || 4096;

	var openaiMessages = base.convertMessages(messages, config.systemPrompt);

	var body = {
		max_completion_tokens: maxTokens,
		messages: openaiMessages
	};

	var toolsArray = base.buildTools(tools);
	if (toolsArray) {
		body.tools = toolsArray;
	}

	return {
		url: endpoint + "/openai/deployments/" + deployment + "/chat/completions?api-version=" + apiVersion,
		headers: {
			"api-key": config.apiKey,
			"Content-Type": "application/json"
		},
		body: JSON.stringify(body)
	};
};

exports.parseResponse = base.parseResponse;
exports.buildToolResult = base.buildToolResult;
exports.buildAssistantMessage = base.buildAssistantMessage;
exports.buildFileBlock = base.buildFileBlock;

exports.buildModelListRequest = function(config) {
	var endpoint = (config.endpoint || "").replace(/\/+$/, "");
	var apiVersion = config.apiVersion || "2025-04-01-preview";
	return {
		url: endpoint + "/openai/models?api-version=" + apiVersion,
		headers: { "api-key": config.apiKey }
	};
};

exports.parseModelListResponse = function(responseText) {
	var data = JSON.parse(responseText);
	return (data.data || [])
		.filter(function(m) { return m.capabilities && m.capabilities.chat_completion; })
		.map(function(m) { return { id: m.id, label: m.id }; })
		.sort(function(a, b) { return a.label.localeCompare(b.label); });
};

})();
","type":"application/javascript","module-type":"library"},"$:/plugins/rimir/llm-connect/adapter-claude":{"title":"$:/plugins/rimir/llm-connect/adapter-claude","text":"/*\
title: $:/plugins/rimir/llm-connect/adapter-claude
type: application/javascript
module-type: library

Claude (Anthropic) API adapter

\*/
(function() {

"use strict";

exports.name = "claude";

exports.buildRequest = function(messages, tools, config) {
	var apiKey = config.apiKey;
	var model = config.model || "claude-sonnet-4-20250514";
	var maxTokens = parseInt(config.maxTokens) || 4096;

	var body = {
		model: model,
		max_tokens: maxTokens,
		messages: convertMessages(messages)
	};

	if (config.systemPrompt) {
		body.system = config.systemPrompt;
	}

	if (tools && tools.length > 0) {
		body.tools = tools.map(function(t) {
			return {
				name: t.name,
				description: t.description,
				input_schema: t.schema
			};
		});
	}

	return {
		url: "https://api.anthropic.com/v1/messages",
		headers: {
			"x-api-key": apiKey,
			"anthropic-version": "2023-06-01",
			"content-type": "application/json",
			"anthropic-dangerous-direct-browser-access": "true"
		},
		body: JSON.stringify(body)
	};
};

exports.parseResponse = function(responseText) {
	var data = JSON.parse(responseText);
	var result = {
		type: "text",
		content: "",
		toolCalls: [],
		usage: data.usage || null
	};

	if (data.stop_reason === "tool_use" || data.stop_reason === "end_turn") {
		var textParts = [];
		var toolCalls = [];

		for (var i = 0; i < data.content.length; i++) {
			var block = data.content[i];
			if (block.type === "text") {
				textParts.push(block.text);
			} else if (block.type === "tool_use") {
				toolCalls.push({
					id: block.id,
					name: block.name,
					input: block.input
				});
			}
		}

		if (toolCalls.length > 0) {
			result.type = "tool_use";
			result.toolCalls = toolCalls;
			result.content = textParts.join("\n");
		} else {
			result.type = "text";
			result.content = textParts.join("\n");
		}
	}

	return result;
};

exports.buildToolResult = function(toolCallId, resultContent) {
	return {
		role: "user",
		content: [{
			type: "tool_result",
			tool_use_id: toolCallId,
			content: typeof resultContent === "string" ? resultContent : JSON.stringify(resultContent)
		}]
	};
};

exports.buildAssistantMessage = function(parsed) {
	var content = [];
	if (parsed.content) {
		content.push({ type: "text", text: parsed.content });
	}
	for (var i = 0; i < parsed.toolCalls.length; i++) {
		var tc = parsed.toolCalls[i];
		content.push({
			type: "tool_use",
			id: tc.id,
			name: tc.name,
			input: tc.input
		});
	}
	return { role: "assistant", content: content };
};

exports.buildModelListRequest = function(config) {
	return {
		url: "https://api.anthropic.com/v1/models?limit=100",
		headers: {
			"x-api-key": config.apiKey,
			"anthropic-version": "2023-06-01",
			"anthropic-dangerous-direct-browser-access": "true"
		}
	};
};

exports.parseModelListResponse = function(responseText) {
	var data = JSON.parse(responseText);
	return (data.data || [])
		.map(function(m) { return { id: m.id, label: m.display_name || m.id }; })
		.sort(function(a, b) { return a.label.localeCompare(b.label); });
};

exports.buildFileBlock = function(fileData) {
	if (fileData.category === "image") {
		return {
			type: "image",
			source: { type: "base64", media_type: fileData.mediaType, data: fileData.base64 }
		};
	}
	if (fileData.category === "document") {
		return {
			type: "document",
			source: { type: "base64", media_type: fileData.mediaType, data: fileData.base64 }
		};
	}
	return { type: "text", text: "[Unsupported file: " + fileData.filename + " (" + fileData.mediaType + ")]" };
};

function convertMessages(messages) {
	var result = [];
	for (var i = 0; i < messages.length; i++) {
		var msg = messages[i];
		if (msg.role === "assistant") {
			// Normalize OpenAI-format assistant messages to Claude format
			if (msg.tool_calls && msg.tool_calls.length > 0) {
				var content = [];
				if (msg.content) {
					content.push({ type: "text", text: msg.content });
				}
				for (var t = 0; t < msg.tool_calls.length; t++) {
					var tc = msg.tool_calls[t];
					content.push({
						type: "tool_use",
						id: tc.id,
						name: tc["function"].name,
						input: typeof tc["function"].arguments === "string" ? JSON.parse(tc["function"].arguments) : tc["function"].arguments
					});
				}
				result.push({ role: "assistant", content: content });
			} else {
				result.push({ role: "assistant", content: msg.content || "" });
			}
		} else if (msg.role === "tool") {
			// Convert OpenAI tool result to Claude format
			var prev = result.length > 0 ? result[result.length - 1] : null;
			var toolResult = { type: "tool_result", tool_use_id: msg.tool_call_id, content: msg.content || "" };
			if (prev && prev.role === "user" && Array.isArray(prev.content) && prev.content[0] && prev.content[0].type === "tool_result") {
				prev.content.push(toolResult);
			} else {
				result.push({ role: "user", content: [toolResult] });
			}
		} else if (msg.role === "user") {
			result.push({ role: "user", content: msg.content });
		}
	}
	return result;
}

})();
","type":"application/javascript","module-type":"library"},"$:/plugins/rimir/llm-connect/adapter-openai-base":{"title":"$:/plugins/rimir/llm-connect/adapter-openai-base","text":"/*\
title: $:/plugins/rimir/llm-connect/adapter-openai-base
type: application/javascript
module-type: library

Shared base for OpenAI-compatible adapters (OpenAI, Azure)

\*/
(function() {

"use strict";

/*
Parse an OpenAI-format chat completion response.
Returns { type, content, toolCalls, usage }.
*/
exports.parseResponse = function(responseText) {
	var data = JSON.parse(responseText);
	if (!data.choices || !data.choices[0]) {
		throw new Error("Invalid API response: missing choices array");
	}
	var choice = data.choices[0];
	var message = choice.message;
	var result = {
		type: "text",
		content: message.content || "",
		toolCalls: [],
		usage: data.usage || null
	};

	if (message.tool_calls && message.tool_calls.length > 0) {
		result.type = "tool_use";
		result.toolCalls = message.tool_calls.map(function(tc) {
			return {
				id: tc.id,
				name: tc["function"].name,
				input: JSON.parse(tc["function"].arguments)
			};
		});
	}

	return result;
};

/*
Build a tool result message in OpenAI format.
*/
exports.buildToolResult = function(toolCallId, resultContent) {
	return {
		role: "tool",
		tool_call_id: toolCallId,
		content: typeof resultContent === "string" ? resultContent : JSON.stringify(resultContent)
	};
};

/*
Build an assistant message from parsed response (OpenAI format).
*/
exports.buildAssistantMessage = function(parsed) {
	var msg = {
		role: "assistant",
		content: parsed.content || null
	};
	if (parsed.toolCalls.length > 0) {
		msg.tool_calls = parsed.toolCalls.map(function(tc) {
			return {
				id: tc.id,
				type: "function",
				"function": {
					name: tc.name,
					arguments: JSON.stringify(tc.input)
				}
			};
		});
	}
	return msg;
};

/*
Build an adapter-specific file content block (OpenAI format).
*/
exports.buildFileBlock = function(fileData) {
	if (fileData.category === "image") {
		return {
			type: "image_url",
			image_url: { url: "data:" + fileData.mediaType + ";base64," + fileData.base64 }
		};
	}
	if (fileData.category === "document") {
		return {
			type: "file",
			file: { filename: fileData.filename, file_data: "data:" + fileData.mediaType + ";base64," + fileData.base64 }
		};
	}
	return { type: "text", text: "[Unsupported file: " + fileData.filename + " (" + fileData.mediaType + ")]" };
};

/*
Build OpenAI-format tools array from internal tool definitions.
*/
exports.buildTools = function(tools) {
	if (!tools || tools.length === 0) return undefined;
	return tools.map(function(t) {
		return {
			type: "function",
			"function": {
				name: t.name,
				description: t.description,
				parameters: t.schema
			}
		};
	});
};

/*
Convert internal message format to OpenAI-compatible format.
Handles Claude-format assistant messages, tool_result arrays, and multimodal content.
*/
exports.convertMessages = function(messages, systemPrompt) {
	var result = [];
	if (systemPrompt) {
		result.push({ role: "system", content: systemPrompt });
	}
	for (var i = 0; i < messages.length; i++) {
		var msg = messages[i];
		if (msg.role === "assistant" && Array.isArray(msg.content)) {
			// Convert Claude-format assistant message to OpenAI format
			var text = "";
			var toolCalls = [];
			for (var j = 0; j < msg.content.length; j++) {
				var block = msg.content[j];
				if (block.type === "text") {
					text += (text ? "\n" : "") + block.text;
				} else if (block.type === "tool_use") {
					toolCalls.push({
						id: block.id,
						type: "function",
						"function": {
							name: block.name,
							arguments: JSON.stringify(block.input)
						}
					});
				}
			}
			var converted = { role: "assistant", content: text || null };
			if (toolCalls.length > 0) {
				converted.tool_calls = toolCalls;
			}
			result.push(converted);
		} else if (msg.role === "user" && Array.isArray(msg.content)) {
			// Check if this is a tool_result array or a multimodal content array
			var hasToolResult = false;
			var hasMultimodal = false;
			for (var p = 0; p < msg.content.length; p++) {
				if (msg.content[p].type === "tool_result") hasToolResult = true;
				if (msg.content[p].type === "text" || msg.content[p].type === "image_url" || msg.content[p].type === "file" || msg.content[p].type === "image" || msg.content[p].type === "document") hasMultimodal = true;
			}
			if (hasToolResult) {
				for (var k = 0; k < msg.content.length; k++) {
					var item = msg.content[k];
					if (item.type === "tool_result") {
						result.push({
							role: "tool",
							tool_call_id: item.tool_use_id,
							content: typeof item.content === "string" ? item.content : JSON.stringify(item.content)
						});
					} else if (typeof item === "string") {
						result.push({ role: "user", content: item });
					}
				}
			} else if (hasMultimodal) {
				// Convert Claude-format image/document blocks to OpenAI format
				var contentParts = [];
				for (var m = 0; m < msg.content.length; m++) {
					var block = msg.content[m];
					if (block.type === "text") {
						contentParts.push(block);
					} else if (block.type === "image_url" || block.type === "file") {
						contentParts.push(block);
					} else if (block.type === "image" && block.source) {
						contentParts.push({
							type: "image_url",
							image_url: { url: "data:" + block.source.media_type + ";base64," + block.source.data }
						});
					} else if (block.type === "document" && block.source) {
						contentParts.push({
							type: "file",
							file: { filename: "document.pdf", file_data: "data:" + block.source.media_type + ";base64," + block.source.data }
						});
					}
				}
				result.push({ role: "user", content: contentParts });
			}
		} else {
			result.push(msg);
		}
	}
	return result;
};

})();
