title: $:/plugins/rimir/llm-connect/adapter-openai
type: application/javascript
module-type: library

OpenAI API adapter

\*/
(function() {

"use strict";

var base = require("$:/plugins/rimir/llm-connect/adapter-openai-base");

exports.name = "openai";

exports.buildRequest = function(messages, tools, config) {
	var apiKey = config.apiKey;
	var model = config.model || "gpt-4o";
	var maxTokens = parseInt(config.maxTokens) || 4096;

	var openaiMessages = base.convertMessages(messages, config.systemPrompt);

	var body = {
		model: model,
		max_completion_tokens: maxTokens,
		messages: openaiMessages
	};

	var toolsArray = base.buildTools(tools);
	if (toolsArray) {
		body.tools = toolsArray;
	}

	return {
		url: "https://api.openai.com/v1/chat/completions",
		headers: {
			"Authorization": "Bearer " + apiKey,
			"Content-Type": "application/json"
		},
		body: JSON.stringify(body)
	};
};

exports.parseResponse = base.parseResponse;
exports.buildToolResult = base.buildToolResult;
exports.buildAssistantMessage = base.buildAssistantMessage;
exports.buildFileBlock = base.buildFileBlock;

exports.buildModelListRequest = function(config) {
	return {
		url: "https://api.openai.com/v1/models",
		headers: { "Authorization": "Bearer " + config.apiKey }
	};
};

exports.parseModelListResponse = function(responseText) {
	var data = JSON.parse(responseText);
	return (data.data || [])
		.filter(function(m) {
			return /^(gpt-|o[134]-|chatgpt-)/.test(m.id) && !/(-instruct|-realtime|-audio|-transcri)/.test(m.id);
		})
		.map(function(m) { return { id: m.id, label: m.id }; })
		.sort(function(a, b) { return a.label.localeCompare(b.label); });
};

})();
","type":"application/javascript","module-type":"library"},"$:/plugins/rimir/llm-connect/changelog":{"title":"$:/plugins/rimir/llm-connect/changelog","created":"20260310120000000","modified":"20260310120000000","type":"text/vnd.tiddlywiki","text":"! Changelog

|!Version |!Date |!Changes |
|0.1.53 |2026-04-25 |TW 5.4.0 compat: `$click-outside` widget cleanup hook renamed from `removeChildDomNodes` to `onDestroy` (PR #9097). Parent widgets in 5.4.0 destroy children via `destroyChildren → child.destroy() → onDestroy()` and never call the legacy `removeChildDomNodes` on that path, so the document-level mousedown listener was leaking on chat-panel teardown |
|0.1.52 |2026-04-13 |Default tool-selector init restricted to `tool-category: core` instead of all tools. Default help context falls back to `tw-gotchas` when widget's `defaultContext` attribute is unset. `initDefaultHelpContext` now runs at widget mount (execute) so the context selector popup reflects defaults immediately. Context-tree toggle icons switched to VS15 text-presentation (monochrome, no emoji squares) and enlarged (font-size 8px → 11px, opacity 0.5 → 0.7) |
|0.1.51 |2026-04-09 |file-pipeline integration: `extractDocument()` delegates to file-pipeline when installed (falls back to legacy `/api/extract`). `isExtractable()` checks pipeline definitions. Extraction config migrating to file-pipeline namespace |
|0.1.50 |2026-04-08 |Add 135 Jasmine tests: adapter-openai-base, adapter-claude, adapter-openai, adapter-azure, widget-helpers, file-resolver, orchestrator |
|0.1.49 |2026-04-07 |Cleanup: replace \define with \function, inline backtick templates for filter strings |
|v0.1.48 |2026-04-07 |Artifact lifecycle fields — `.extracted` tiddlers and summaries now carry `_artifact_source` and `_artifact_type` for cascade delete/rename (requires file-upload). Multi-file PDF extraction — optional `pdfimages` support extracts embedded images alongside text, stored as `extraction-image` tiddlers in `files/_derived/`. New `extract-images` config toggle. Relink field config for `extraction-source`. Reference docs updated with artifact fields |
|v0.1.47 |2026-04-02 |Fix `+[unique[]join[ ]]` chaining bug — `join` must be in its own `+` run or `{{{ }}}` returns only the first item. Affects context tree (selecting parent node only wrote first descendant) and tool selector (category toggle). Fix debug menu tristate indicator (querySelector matched wrong class after first update). Active Tools debug panel now shows actual resolved tools before first selector click. Remove debug tooltip from context tree. Update reference + architecture docs for debug panel system |
|v0.1.46 |2026-04-02 |Extensible debug panel system — single 🐛 button opens dropdown menu with pluggable inspection panels. Built-in JS panels: Request Preview, Last Request Sent, Last Response, Accessible Tiddlers (with drag-drop), Logging. Tristate tool-call display (No/Brief/Detailed) with animated working indicator. Token estimate moved to toolbar header. Debug panel renders below textarea, toolbar pinned at bottom. Wikitext panel support via `$:/tags/rimir/llm-connect/debug-panel` tag. Active Tools debug panel shows internal tool state. Orchestrator logging — timestamped entries for send/request/response/tool execution/tier routing/errors. Removed: standalone accessible tiddlers button, tool toggle button, help context button+panel from bottom bar |
|v0.1.45 |2026-04-01 |Document extraction — PDF/DOCX/XLSX files auto-converted to markdown text (via pdftotext/pandoc/openpyxl) before sending to LLM. Cached per document as `.extracted` tiddler. Extraction toggle + max size in settings. DOCX/XLSX added to `SUPPORTED_MEDIA`. Model tier routing infrastructure — `tool-model-tier` field on tools (cheap/default/expensive), per-tier provider/model config, orchestrator switches model per tool round. Tier column in settings tool table. Chat tiddler auto-added to allow filter for `attach_document` writability |
|v0.1.44 |2026-04-01 |`attach_document` tool — LLM can attach binary files (PDF, DOCX, XLSX) mid-conversation for multimodal reading. Pending attachments resolved after each tool round via file-resolver. `__chatTiddler` variable injected into tool execution context. Restricted wiki `addTiddler` now allows creating new tiddlers (only blocks overwriting existing protected ones) |
|v0.1.43 |2026-04-01 |Tree-based tool selector — tools grouped by `tool-category` with tri-state checkboxes (like context tree). Add `tool-category` field to all tool tiddlers (core, pdf). Remove flat checkbox list and group buttons |
|v0.1.42 |2026-03-30 |Cleanup: add `console.warn` to silent catch blocks in orchestrator/context-resolver (hook errors, model cache parse, output-fields JSON). Add input validation before substring ops in tool-executor and context-resolver. Add API response format check in adapter-openai-base. Startup module loading now reports which specific module failed |
|v0.1.41 |2026-03-30 |Hierarchical help context selector — collapsible tree with tri-state checkboxes replaces flat list. Parent-child cascading: check parent checks all descendants, partial selection shows indeterminate state. Tree derived from `/`-delimited context keys. New `defaultContext` widget attribute (space-separated prefixes) for per-panel default selection. Help context debug panel in button row shows raw active keys. `__helpContext` injected as built-in tool variable (replaces shared temp tiddler sync). `llm-help-context-init` in `CHAT_STATE_FIELDS` for pin/save/restore. Tree defaults to 2 levels expanded |
|v0.1.40 |2026-03-30 |Fix: hard protection display now shows `-` prefix in allow mode to reflect actual filter semantics. Fix: help pages always accessible regardless of protection mode — adds help page access layer after hard protection so `llm_help` tool works in restrictive contexts like pair-edit whitelist. Only active when llm-help plugin is installed |
|v0.1.39 |2026-03-30 |Base + hard protection filters. Base protection (`$:/config/rimir/llm-connect/base-protection-filter`, default `[tag[sensitive]]`) is part of the base filter chain. Hard protection (`$:/config/rimir/llm-connect/hard-protection-filter`, default `[tag[sensitive]]`) is the final safety net — applied after all user input, shown with lock icon below the per-chat filter input. Uses `{tiddler-reference}` indirection in `subfilter` to avoid nested-bracket parsing. Deny-mode default filter cleared (sensitive handling moved to base/hard). Pair-edit `allowFilter` uses `\define` with `$(currentTiddler)$` substitution for a readable dynamic filter. Per-chat input no longer pre-filled with widget attribute |
|v0.1.38 |2026-03-30 |Pair-edit always starts in allow (whitelist) mode. Base filter display now includes widget-level `allowFilter`/`denyFilter` attributes so users see the full effective filter |
|v0.1.37 |2026-03-30 |Set default allow-filter to include all llm-help pages and functions. Pair-edit: auto-allow current tiddler + its links + child tiddlers (prefix/) in allow mode |
|v0.1.36 |2026-03-30 |Per-chat help context — `llm-help-context` field on each chat tiddler replaces the shared global tiddler. Context selector popup state is now per-chat. Before tool execution, the chat's context is synced to the global tiddler so `llm_help` picks it up. Persisted with pin/save/restore |
|v0.1.35 |2026-03-30 |Consolidate tool-selector and context-selector into `chat-toolbar.tid` — eliminates `$importvariables` nesting that caused widget tree rebuilds. `$click-outside` widget: global handler registry prevents duplicates, `wrapper.contains()` for robust hit testing. Drag handler skips interactive elements (checkboxes, labels) inside header. Remove dead `tool-selector.tid` and `context-selector.tid` |
|v0.1.34 |2026-03-29 |Help context selector (? icon) in chat header — toggle llm-help context keys per chat. All/None quick buttons + context groups (tag `$:/tags/rimir/llm-connect/context-group`). Only visible when llm-help plugin is installed and contexts exist. Shared chat toolbar (`chat-toolbar.tid`) — pin, export/import, tool selector, context selector defined once, used by all chat panels (global, view, pair-edit, appify). Fix `$click-outside` widget: use `wrapper.contains()` instead of class-based check, auto-cleanup stale handlers. Fix `navigate_to_tiddler` splitting titles with spaces. Fix system prompt body split across field header and tiddler body |
|v0.1.33 |2026-03-29 |Chat export/import — arrow buttons in chat header copy conversation as JSON to clipboard (export) or restore from clipboard/paste dialog (import). All state preserved: messages, provider, model, tools, protection, context filter |
|v0.1.32 |2026-03-29 |Add tw-gotchas reminder to default system prompt — LLM must read gotchas before writing wikitext/filters |
|v0.1.31 |2026-03-28 |Fix docs: update security.tid deny filter default to match actual value (`[tag[sensitive]]`), remove stale reference to `prefix[$:/plugins/rimir/]` blocking |
|v0.1.30 |2026-03-28 |Remove "Creation rules" setting — naming conventions belong in context-specific llm-help pages, not as a global system prompt injection |
|v0.1.29 |2026-03-28 |Markdown rendering for assistant messages (uses TW markdown plugin). Collapsible tool messages — collapsed by default, per-message click or chat-wide toggle (⚙️ button). Plugin visibility settings — tick plugins to exclude their shadows from LLM access. Simplified default deny filter to `[tag[sensitive]]`. Restricted wiki proxy: own filter cache + shadow iteration overrides fix shadow tiddler access. Accessible tiddlers panel now includes shadows, auto-refreshes on protection config changes. Auto-focus textarea on chat open |
|v0.1.28 |2026-03-28 |Switch default protection to deny mode. Deny-filter blocks plugin internals and sensitive tiddlers but exempts llm-help pages, typed schema definitions, and supporting functions so the llm_help tool works. Revert allow-filter to empty. |
|v0.1.27 |2026-03-28 |Add llm-help pages to base allow-filter so LLM can read help documentation via llm_help tool |
|v0.1.26 |2026-03-27 |Fix docs: add missing Azure OpenAI mentions in overview (description, features, prerequisites). Remove stale json-dsl dependency from dev-workflow (not actually used) |
|v0.1.25 |2026-03-26 |Refactor: extract `CHAT_STATE_FIELDS` constant (dedup field-copy lists in pin save/restore). Extract `saveChatField()` helper (dedup protection field save pattern). Fix result title regex with `$` anchor for titles containing single quotes. Array join for proxy expansion candidates. 9 new Playwright E2E tests for v0.1.18-v0.1.24 features (pin, accessible tiddlers panel, filter negation, basetitle schema, creation rules, protection mode) |
|v0.1.24 |2026-03-25 |Pin button moved to wikitext header templates (chat-panel, pair-edit, chat-view). Pin context menu adds "Clear all" option (deletes saved chat + clears conversation). Fix: restricted wiki proxy now temporarily allows writing new (non-existing) titles during `create_tiddler` — prevents silent write failure in allow mode. Fix: `pin()` creates chat tiddler on-the-fly when pinning an empty chat. Existing tiddlers remain protected from overwrite |
|v0.1.23 |2026-03-25 |`create_tiddler` basetitle support — new `basetitle` parameter auto-numbers titles if taken (e.g. `Note`, `Note 1`, `Note 2`). Returns actual title created. Mutually exclusive with `title` (exact mode). Orchestrator extracts resolved title from result for protection filter. New "Creation rules" setting — natural-language text appended to system prompt to guide LLM naming conventions |
|v0.1.22 |2026-03-25 |Auto-add created tiddlers to protection filter — `create_tiddler` tool now adds new titles to the allow/deny filter so subsequent tool calls can access them. Block overwriting existing tiddlers via `create_tiddler` (returns error, directs LLM to use `set_field`). Protected tiddlers cannot be overwritten even via create. Protection filter changes persisted to chat tiddler after tool loop |
|v0.1.21 |2026-03-25 |Chat pin/save/restore — 📌 icon pins a chat to persist it to disk (`$:/saved-chats/...`). Pinned chats auto-sync all state (messages, protection, tools, context filter, injection flags). Restore on reload via pin icon. Context menu when save exists and chat has messages ("Save current" / "Restore saved" with confirm). Source tiddler (pair-edit target) automatically added to allow filter. All state changes sync when pinned (protection, context, tools, messages) |
|v0.1.20 |2026-03-25 |Auto-negate per-chat protection filter on mode switch — switching between allow/deny automatically toggles the `-` prefix on each filter run, preserving user intent. Bracket-depth parser handles chained operators like `[tag[x]has[y]]` |
|v0.1.19 |2026-03-24 |Accessible tiddlers panel (👁️ icon) — scrollable list of all tiddlers the LLM can currently access based on active protection filter. Clickable title links for navigation. Drag-and-drop to grant access: adds `[[title]]` to whitelist (allow mode) or `-[[title]]` to blacklist exemption (deny mode). Auto-refreshes on protection mode/filter changes |
|v0.1.18 |2026-03-24 |Refactor: extract `resolveProtectionForChat()`, `injectContextOnFirstMessage()`, `injectLateAttachments()`, `buildAttachmentParts()` from chat-widget (sendMessage was 195 lines). DRY restricted wiki proxy with `guardRead()` factory. Simplify file extension matching (`endsWith`). Fix docs: remove non-existent `!tag[$:/tags/rimir/llm-accessible]` from deny filter docs. Fix chat-view tool filter to include shadow tiddlers. Replace hardcoded CSS color with theme variable |
|v0.1.17 |2026-03-19 |Allow/deny protection modes — default allow (whitelist, LLM has no access until filter defined) with deny (blacklist) option. Separate base filters per mode. `protectionMode`, `allowFilter`, `denyFilter` attributes on `<$llm-chat>` and `<$llm-action>`. Per-chat mode switching via shield icon dropdown. Per-chat `llm-allow-filter`/`llm-deny-filter` fields. Restricted wiki proxy no longer post-filters `filterTiddlers` results — filter operators use overridden accessors via prototype chain. Fix SVG icon tiddlers (removed `type: image/svg+xml` — now inline like TW core icons) |
|v0.1.16 |2026-03-15 |Add recipe/tools-panel system, PDF summarization, missing doc tiddlers |
|v0.1.15 |2026-03-15 |Extract inline SVGs to icon tiddlers |
|v0.1.14 |2026-03-15 |Add regression tests and CI test gate |
|v0.1.13 |2026-03-12 |Fix: context attachments (📎) now work when added after the first message — separate `attachmentsInjected` flag allows late injection. Fix: base64 abbreviation in debug panel — relaxed regex, data URI check first, now also applies to Preview tab. Fix: tool toggle via wrench icon now instantly updates the Preview debug tab |
|v0.1.12 |2026-03-12 |Refactor: extracted shared OpenAI-compatible adapter base (`adapter-openai-base.js`) — eliminates ~160 lines of duplication between OpenAI and Azure adapters. New `widget-helpers.js` library centralizes protection filter resolution, tool resolution, and provider config patterns shared by `<$llm-chat>` and `<$llm-action>`. Removed unused `confirm-writes` config tiddler and settings checkbox. Updated `doc-reference.tid` with missing attributes (`toolGroup`, `provider`, `model`, `protectionFilter`, `context` on `<$llm-action>`; `toolGroup` on `<$llm-chat>`), debug panel docs, and token estimate docs |
|v0.1.11 |2026-03-12 |Response tab in debug panel — shows raw API response JSON (base64 abbreviated). Protection filter row now shows base filter from settings as read-only label with `+` separator before the per-chat input. `<$llm-action>` feature parity with `<$llm-chat>`: new `provider`, `model`, `protectionFilter` attributes. New `toolGroup` attribute on both widgets — resolves tool group by name, restricts tools to group members. `resolveToolGroup()` helper in tool-executor |
|v0.1.9 |2026-03-12 |Token estimate display in chat button row — shows `~3.2k tok (1.8k in / 1.4k out)` next to model selector, split by assistant (in) and user+context+tools (out). Counts only actual text content, skips base64 image/document data. Updates live on every message exchange. Hover tooltip shows exact character counts |
|v0.1.8 |2026-03-12 |Azure API version default updated to `2025-04-01-preview`. Context filter error detection — broken attachment filters now abort the send, show the error in the status bar, and preserve the user's input instead of silently injecting broken context into the conversation |
|v0.1.7 |2026-03-12 |Multimodal context — attach PDFs and images to conversations via context filter (📎 icon); file-resolver detects `_canonical_uri` files, classifies as image/document, fetches and base64-encodes just before API call. Debug panel (🐛 icon) with live Preview and Sent tabs; added/removed from DOM on toggle for clean layout. Resizable chat panel and chat history. Real-time debug preview updates on input changes. New security documentation section |
|v0.1.6 |2026-03-11 |Restricted wiki proxy — all tool wikitext now executes against a proxy wiki (`Object.create($tw.wiki)`) that hides protected tiddlers at every access point (getTiddler, filterTiddlers, each, addTiddler, etc.). Default filter expanded to also protect rimir plugin internals (`$:/plugins/rimir/`). Settings UI: active filter display with "(default)"/"(custom)" label, reset-to-default button. Removed redundant subfilter subtraction from search-tiddlers tool |
|v0.1.5 |2026-03-11 |Tiddler protection filters — base filter in settings (always active, `[tag[sensitive]]` by default) + per-chat filter via shield icon. Protected tiddlers cannot be read, modified, deleted, or found via search. Protection enforced at tool-executor level (title check) and in search results (subfilter subtraction). `<<protectionFilter>>` variable available in custom tool wikitext |
|v0.1.4 |2026-03-11 |Azure OpenAI provider adapter. Dynamic model selection — fetch available models from provider APIs, global default model in settings, per-chat model selector dropdown. Provider/model locking after first message (lock icon + tooltip hint). Clear chat button to reset conversation and unlock model. Cross-provider message format conversion (Claude ↔ OpenAI/Azure). Fetch models directly from chat dropdown when no models cached |
|v0.1.3 |2026-03-11 |Per-chat tool selection — wrench icon in chat header opens click-outside-to-close dropdown to toggle individual tools per chat instance. Tool groups as presets (configured in settings, applied in chat selector). `llm-active-tools` field on chat tiddler. All/None quick buttons. Group management UI in settings. Orchestrator enforces allowed tools at execution time (defense-in-depth). Default tool set: built-in (shadow) tools only. Fixed init filter (`get` + `else` pattern for missing fields). `<$click-outside>` utility widget |
|v0.1.2 |2026-03-11 |Tool management settings UI — tool table with expand/collapse detail view (schema, wikitext body), inline editing for custom tools, clone tool, active/inactive toggle (`tool-enabled` field), completeness validation (incomplete tools cannot be activated or cloned). Fixed `get_tiddler` returning rendered content instead of raw source. Documented variables available in tool wikitext |
|v0.1.1 |2026-03-11 |Wikitext-native tools — tool logic moved from hardcoded JS handlers into tiddler text fields (read mode: render wikitext, action mode: invoke action widgets). Replaced `tool-handler` with `tool-mode` field. Simplified `create_tiddler` schema (explicit `tags` param instead of generic `fields` object). Fixed `<%if%>`/`invokeActions` incompatibility in action tools by using `<$list>`+`emptyMessage` pattern |
|v0.1.0 |2026-03-10 |Initial release — provider adapters (Claude, OpenAI), tool system (search, read, set-field, create, delete, navigate), orchestrator, chat widget, action widget, context templates, pair editing (toolbar button + embedded panel), draggable chat panel, audit logging for write operations, 12 bundled examples |
