"},"$:/plugins/rimir/llm-connect/startup":{"title":"$:/plugins/rimir/llm-connect/startup","text":"/*\
title: $:/plugins/rimir/llm-connect/startup
type: application/javascript
module-type: startup

Browser startup — initialize provider, verify configuration, register message handlers

\*/
(function() {

"use strict";

exports.name = "llm-connect-startup";
exports.platforms = ["browser"];
exports.after = ["startup"];

exports.startup = function() {
	// Verify modules are loadable
	var modules = [
		"orchestrator", "tool-executor", "context-resolver",
		"adapter-claude", "adapter-openai-base", "adapter-openai",
		"adapter-azure", "widget-helpers"
	];
	for (var i = 0; i < modules.length; i++) {
		try {
			require("$:/plugins/rimir/llm-connect/" + modules[i]);
		} catch(e) {
			console.error("llm-connect: Failed to load " + modules[i] + ":", e);
		}
	}

	// Handle tm-llm-fetch-models message
	$tw.rootWidget.addEventListener("tm-llm-fetch-models", function(event) {
		var provider = event.paramObject && event.paramObject.provider;
		if (!provider) return;
		var orchestrator = require("$:/plugins/rimir/llm-connect/orchestrator");
		var statusTiddler = "$:/temp/rimir/llm-connect/fetch-status/" + provider;
		$tw.wiki.setText(statusTiddler, "text", null, "Fetching...");
		orchestrator.fetchModels(provider).then(function(models) {
			$tw.wiki.setText(statusTiddler, "text", null, models.length + " models loaded");
		})["catch"](function(err) {
			$tw.wiki.setText(statusTiddler, "text", null, "Error: " + err.message);
		});
	});
};

})();
","type":"application/javascript","module-type":"startup"},"$:/plugins/rimir/llm-connect/styles":{"title":"$:/plugins/rimir/llm-connect/styles","tags":"$:/tags/Stylesheet","type":"text/vnd.tiddlywiki","text":".llm-chat-container {
	display: flex;
	flex-direction: column;
	border: 1px solid <<colour tiddler-border>>;
	border-radius: 4px;
	overflow: hidden;
}

/* Pin button */

.llm-chat-pin-wrapper {
	display: inline-block;
	position: relative;
	vertical-align: middle;
}

.llm-chat-panel-header-left {
	display: flex;
	align-items: center;
	gap: 4px;
}

.llm-chat-btn-pin {
	background: none;
	border: none;
	cursor: pointer;
	font-size: 1.1em;
	padding: 2px 4px;
	opacity: 0.5;
	filter: grayscale(1);
	transition: opacity 0.15s, filter 0.15s;
}

.llm-chat-btn-pin:hover {
	opacity: 0.8;
}

.llm-chat-btn-pin-active {
	opacity: 1;
	filter: none;
}

.llm-chat-btn-pin-has-save {
	opacity: 0.6;
	filter: grayscale(1);
}

.llm-chat-btn-pin-has-save::after {
	content: "";
	display: inline-block;
	width: 6px;
	height: 6px;
	background: <<colour primary>>;
	border-radius: 50%;
	margin-left: 2px;
	vertical-align: top;
}

.llm-chat-pin-menu {
	position: absolute;
	left: 0;
	top: 100%;
	background: <<colour tiddler-background>>;
	border: 1px solid <<colour tiddler-border>>;
	border-radius: 4px;
	box-shadow: 0 2px 8px rgba(0,0,0,0.15);
	z-index: 100;
	min-width: 140px;
}

.llm-chat-pin-menu-item {
	padding: 6px 12px;
	cursor: pointer;
	font-size: 0.85em;
	white-space: nowrap;
}

.llm-chat-pin-menu-item:hover {
	background: <<colour notification-background>>;
}

.llm-chat-pin-menu-item-danger {
	color: <<colour dirty-indicator>>;
}

.llm-chat-pin-menu-item-danger:hover {
	background: <<colour dirty-indicator>>;
	color: <<colour background>>;
}

/* Export/Import buttons */
.llm-chat-io-wrapper {
	display: inline-flex;
	align-items: center;
	gap: 2px;
}

.llm-chat-btn-export,
.llm-chat-btn-import {
	padding: 2px 4px;
	vertical-align: middle;
	opacity: 0.6;
	transition: opacity 0.15s;
}

.llm-chat-btn-export:hover,
.llm-chat-btn-import:hover {
	opacity: 1;
}

.llm-chat-btn-export svg,
.llm-chat-btn-import svg {
	vertical-align: middle;
}

/* Import dialog */
.llm-chat-import-overlay {
	position: fixed;
	top: 0;
	left: 0;
	right: 0;
	bottom: 0;
	background: rgba(0,0,0,0.4);
	z-index: 10000;
	display: flex;
	align-items: center;
	justify-content: center;
}

.llm-chat-import-dialog {
	background: <<colour tiddler-background>>;
	color: <<colour foreground>>;
	border: 1px solid <<colour tiddler-border>>;
	border-radius: 8px;
	padding: 16px;
	width: 500px;
	max-width: 90vw;
	box-shadow: 0 4px 16px rgba(0,0,0,0.2);
}

.llm-chat-import-textarea {
	width: 100%;
	height: 200px;
	font-family: monospace;
	font-size: 0.85em;
	border: 1px solid <<colour tiddler-border>>;
	border-radius: 4px;
	padding: 8px;
	resize: vertical;
	background: <<colour page-background>>;
	color: <<colour foreground>>;
}

.llm-chat-import-btn {
	padding: 6px 16px;
	border: 1px solid <<colour tiddler-border>>;
	border-radius: 4px;
	background: <<colour page-background>>;
	color: <<colour foreground>>;
	cursor: pointer;
}

.llm-chat-import-btn:hover {
	background: <<colour tag-background>>;
}

.llm-chat-import-btn-primary {
	background: <<colour primary>>;
	color: <<colour background>>;
	border-color: <<colour primary>>;
}

.llm-chat-import-btn-primary:hover {
	opacity: 0.9;
}

.llm-chat-messages {
	flex: 1;
	overflow-y: auto;
	padding: 8px;
	min-height: 200px;
	max-height: 400px;
	background: <<colour tiddler-background>>;
}

.llm-chat-message {
	margin: 4px 0;
	padding: 8px 12px;
	border-radius: 8px;
	max-width: 85%;
	word-wrap: break-word;
	white-space: pre-wrap;
	font-size: 0.9em;
	line-height: 1.4;
}

.llm-chat-message-user {
	background: <<colour primary>>;
	color: <<colour background>>;
	margin-left: auto;
	border-bottom-right-radius: 2px;
}

.llm-chat-message-assistant {
	background: <<colour tag-background>>;
	color: <<colour foreground>>;
	margin-right: auto;
	border-bottom-left-radius: 2px;
}

.llm-chat-message-context {
	background: <<colour code-background>>;
	color: <<colour muted-foreground>>;
	margin-left: auto;
	font-size: 0.8em;
	cursor: pointer;
	border: 1px dashed <<colour muted-foreground>>;
}

.llm-chat-message-context.llm-chat-context-expanded {
	font-size: 0.75em;
	color: <<colour code-foreground>>;
	font-family: {{$:/themes/tiddlywiki/vanilla/settings/codefontfamily}};
	max-height: 200px;
	overflow-y: auto;
	cursor: pointer;
}

.llm-chat-message-tool {
	background: <<colour code-background>>;
	color: <<colour code-foreground>>;
	margin-right: auto;
	font-size: 0.8em;
	font-family: {{$:/themes/tiddlywiki/vanilla/settings/codefontfamily}};
	border-left: 3px solid <<colour muted-foreground>>;
	border-radius: 0 8px 8px 0;
	max-height: 1.8em;
	overflow: hidden;
	white-space: nowrap;
	text-overflow: ellipsis;
	cursor: pointer;
	transition: max-height 0.2s ease, white-space 0.1s;
}

.llm-chat-message-tool.llm-chat-tool-expanded {
	max-height: 300px;
	overflow-y: auto;
	white-space: pre-wrap;
	text-overflow: unset;
}

/* Tool display modes (tristate: none / brief / details) */
.llm-chat-tools-none .llm-chat-message-tool {
	display: none;
}

.llm-chat-tools-brief .llm-chat-message-tool {
	display: block;
}

.llm-chat-tools-details .llm-chat-message-tool {
	display: block;
	max-height: 300px;
	overflow-y: auto;
	white-space: pre-wrap;
	text-overflow: unset;
}

/* Working indicator (shown when tool calls are hidden) */
.llm-chat-tool-working {
	background: <<colour code-background>>;
	color: <<colour code-foreground>>;
	margin-right: auto;
	font-size: 0.8em;
	font-family: {{$:/themes/tiddlywiki/vanilla/settings/codefontfamily}};
	border-left: 3px solid <<colour muted-foreground>>;
	border-radius: 0 8px 8px 0;
	padding: 6px 16px;
}

.llm-chat-tool-working-dots span {
	font-size: 1.8em;
	font-weight: bold;
	letter-spacing: 0.2em;
	animation: llm-dot-pulse 1.4s infinite both;
}

.llm-chat-tool-working-dots span:nth-child(2) {
	animation-delay: 0.2s;
}

.llm-chat-tool-working-dots span:nth-child(3) {
	animation-delay: 0.4s;
}

@keyframes llm-dot-pulse {
	0%, 80%, 100% {
		opacity: 0.15;
	}
	40% {
		opacity: 1;
	}
}

.llm-chat-status {
	display: none;
	padding: 4px 12px;
	font-size: 0.85em;
	color: <<colour muted-foreground>>;
	background: <<colour code-background>>;
	font-style: italic;
}

.llm-chat-input-area {
	border-top: 1px solid <<colour tiddler-border>>;
	padding: 8px;
	background: <<colour page-background>>;
	display: flex;
	flex-direction: column;
	overflow: hidden;
}

.llm-chat-textarea {
	width: 100%;
	resize: vertical;
	border: 1px solid <<colour tiddler-border>>;
	border-radius: 4px;
	padding: 8px;
	font-size: 0.9em;
	font-family: inherit;
	background: <<colour tiddler-background>>;
	color: <<colour foreground>>;
	box-sizing: border-box;
	flex-shrink: 0;
}

.llm-chat-textarea:focus {
	outline: none;
	border-color: <<colour primary>>;
}

.llm-chat-button-row {
	display: flex;
	align-items: center;
	justify-content: flex-end;
	gap: 8px;
	margin-top: 6px;
	position: relative;
